 19→
 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→//// Convolution Functions
 26→int32_t riscv_nn_conv_HWC_u8_u8_s8_sym_fast(const u8_t * in_tensor,
 27→                                     const uint16_t in_tensor_dim,
 28→                                     const uint16_t in_tensor_ch,
 29→                                     const q7_t * ker_weight,
 30→                                     const uint16_t out_tensor_ch,
 31→                                     const uint16_t ker_dim,
 32→                                     const uint16_t pad,
 33→                                     const uint16_t stride,
 34→                                     const uint16_t pre_rshift,
 35→                                     const uint16_t out_scale,
 36→                                     const uint16_t post_rshift,
 37→                                     u8_t * out_tensor,
 38→                                     const uint16_t out_tensor_dim,
 39→                                     q15_t * in_tmp_buf)
 40→{
 41→#ifdef ENA_EMPTY_FUN
 42→    //empty body
 43→#else
 44→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
 45→    {
 46→        /* check if the input dimension meets the constraints */
 47→        return -1;
 48→    }
 49→
 50→#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
 51→    /* cache is 512KB, type is u8 */
 52→    uint32_t tiling_size = 256;
 53→    /* num of columnar */
 54→    int col_counter = 0;
 55→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
 56→    unsigned long addr_in_tmp_buf;
 57→
 58→    /*
 59→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 60→     *  im2col are done to output in q15_t format from u8_t input
 61→     */
 62→    const long align_byte = 64;
 63→    u8_t *pBuffer = (u8_t*)in_tmp_buf;
 64→    u8_t *pOut = out_tensor;
 65→    q31_t *dst_q31;
 66→
 67→    q7_t *src2 = (q7_t *)in_tmp_buf
 68→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim * ker_dim; //matrix_A's memory space
 69→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
 70→    addr_in_tmp_buf = (unsigned long)src2;
 71→    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim * ker_dim;
 72→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
 73→    dst_q31 = (q31_t *)addr_in_tmp_buf;
 74→
 75→    /* transpose the kernel_weight for matrix multiplication */
 76→    const long row = out_tensor_ch;
 77→    const long col = ker_dim * ker_dim * in_tensor_ch;
 78→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
 79→
 80→    /* This part implements the im256col function */
 81→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
 82→    {
 83→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 84→        {
 85→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
 86→            {
 87→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
 88→                {
 89→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
 90→                    {
 91→                        /* Filling 0 for out-of-bound paddings */
 92→                        nn_set_zero_u8(pBuffer, sizeof(u8_t) * in_tensor_ch);
 93→                    }
 94→                    else
 95→                    {
 96→                        /* Copying the pixel data to column */
 97→                        nn_dup_u8(in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
 98→                    }
 99→                    pBuffer += in_tensor_ch;
100→                }
101→            }
102→            col_counter++;
103→
104→            /* Computation is filed for [tiling_size] columns */
105→            if (col_counter == tiling_size)
106→            {
107→                pOut = nn_mat_mul_kernel_tiling_u8_u8_s8((u8_t *)in_tmp_buf,
108→                                                         src2,
109→                                                         dst_q31,
110→                                                         pOut,
111→                                                         col_counter,
112→                                                         in_tensor_ch * ker_dim * ker_dim,
113→                                                         out_tensor_ch,
114→                                                         pre_rshift,
115→                                                         out_scale,
116→                                                         post_rshift,
117→                                                         tiling_size);
118→                /* reset */
119→                col_counter = 0;
120→                pBuffer = (u8_t *)in_tmp_buf;
121→            }
122→        }
123→    }
124→
125→    /* check if there is left-over for compute */
126→    pOut = nn_mat_mul_kernel_tiling_u8_u8_s8((u8_t *)in_tmp_buf,
127→                                             src2,
128→                                             dst_q31,
129→                                             pOut,
130→                                             col_counter,
131→                                             in_tensor_ch * ker_dim * ker_dim,
132→                                             out_tensor_ch,
133→                                             pre_rshift,
134→                                             out_scale,
135→                                             post_rshift,
136→                                             tiling_size);
137→#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
138→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
139→
140→    /*
141→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
142→     *  im2col are done to output in q15_t format from q7_t input
143→     */
144→
145→    u8_t     *pBuffer = (u8_t*)in_tmp_buf;
146→    u8_t     *pOut = out_tensor;
147→    int bound_begin = (pad + stride - 1) / stride;
148→    int bound_end   = (in_tensor_dim + pad - ker_dim + stride) / stride;
149→
150→    /*
151→     *  Here we split the entire matrix into three regions depending on the pad situation
152→     *    Top: i_out_y from 0 to pad - 1
153→     * Middle: i_out_y from pad to out_tensor_dim-pad-1
154→     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
155→     */
156→
157→    /* top part */
158→    for (i_out_y = 0; i_out_y < bound_begin; i_out_y++)
159→    {
160→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
161→        {
162→            /* This part implements the im2col function */
163→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
164→            {
165→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
166→                {
167→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
168→                    {
169→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
170→                    }
171→                    else
172→                    {
173→                        nn_dup_u8
174→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
175→                    }
176→                    pBuffer += in_tensor_ch;
177→                }
178→            }
179→
180→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
181→            {
182→                pOut = nn_mat_mul_kernel_u8_2sft(ker_weight,
183→                                                 (u8_t*)in_tmp_buf,
184→                                                 out_tensor_ch,
185→                                                 in_tensor_ch * ker_dim * ker_dim,
186→                                                 pre_rshift,
187→                                                 out_scale,
188→                                                 post_rshift,
189→                                                 pOut);
190→                /* counter reset */
191→                pBuffer = (u8_t *)in_tmp_buf;
192→            }
193→        }
194→    }
195→
196→    /* middle part, here we also divide the x into left, mid and right */
197→    for (; i_out_y < bound_end; i_out_y++)
198→    {
199→        /* left part */
200→        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
201→        {
202→            /* This part implements the im2col function */
203→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
204→            {
205→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
206→                {
207→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
208→                    {
209→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
210→                    }
211→                    else
212→                    {
213→                        nn_dup_u8
214→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
215→                    }
216→                    pBuffer += in_tensor_ch;
217→                }
218→            }
219→
220→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
221→            {
222→                pOut = nn_mat_mul_kernel_u8_2sft(ker_weight,
223→                                                 (u8_t*)in_tmp_buf,
224→                                                 out_tensor_ch,
225→                                                 in_tensor_ch * ker_dim * ker_dim,
226→                                                 pre_rshift,
227→                                                 out_scale,
228→                                                 post_rshift,
229→                                                 pOut);
230→                /* counter reset */
231→                pBuffer = (u8_t *)in_tmp_buf;
232→            }
233→        }
234→
235→        /* mid part */
236→        for (; i_out_x < bound_end; i_out_x++)
237→        {
238→            /* This part implements the im2col function */
239→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
240→            {
241→                nn_dup_u8
242→                ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
243→                pBuffer += in_tensor_ch * ker_dim;
244→            }
245→
246→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
247→            {
248→                pOut = nn_mat_mul_kernel_u8_2sft(ker_weight,
249→                                                 (u8_t*)in_tmp_buf,
250→                                                 out_tensor_ch,
251→                                                 in_tensor_ch * ker_dim * ker_dim,
252→                                                 pre_rshift,
253→                                                 out_scale,
254→                                                 post_rshift,
255→                                                 pOut);
256→                /* counter reset */
257→                pBuffer = (u8_t *)in_tmp_buf;
258→            }
259→        }
260→
261→        /* right part */
262→        for (; i_out_x < out_tensor_dim; i_out_x++)
263→        {
264→            /* This part implements the im2col function */
265→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
266→            {
267→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
268→                {
269→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
270→                    {
271→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
272→                    }
273→                    else
274→                    {
275→                        nn_dup_u8
276→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
277→                    }
278→                    pBuffer += in_tensor_ch;
279→                }
280→            }
281→
282→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
283→            {
284→                pOut = nn_mat_mul_kernel_u8_2sft(ker_weight,
285→                                                 (u8_t*)in_tmp_buf,
286→                                                 out_tensor_ch,
287→                                                 in_tensor_ch * ker_dim * ker_dim,
288→                                                 pre_rshift,
289→                                                 out_scale,
290→                                                 post_rshift,
291→                                                 pOut);
292→                /* counter reset */
293→                pBuffer = (u8_t *)in_tmp_buf;
294→            }
295→        }
296→    }
297→
298→    for (; i_out_y < out_tensor_dim; i_out_y++)
299→    {
300→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
301→        {
302→            /* This part implements the im2col function */
303→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
304→            {
305→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
306→                {
307→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
308→                    {
309→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
310→                    }
311→                    else
312→                    {
313→                        nn_dup_u8
314→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
315→                    }
316→                    pBuffer += in_tensor_ch;
317→                }
318→            }
319→
320→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
321→            {
322→                pOut = nn_mat_mul_kernel_u8_2sft(ker_weight,
323→                                                 (u8_t*)in_tmp_buf,
324→                                                 out_tensor_ch,
325→                                                 in_tensor_ch * ker_dim * ker_dim,
326→                                                 pre_rshift,
327→                                                 out_scale,
328→                                                 post_rshift,
329→                                                 pOut);
330→                /* counter reset */
331→                pBuffer = (u8_t *)in_tmp_buf;
332→            }
333→        }
334→    }
335→
336→    /* check if there is left-over for compute */
337→#ifdef ENA_VEC_ISA
338→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
339→    if (pBuffer != (u8_t *)in_tmp_buf)
340→    {
341→        unsigned vl;
342→        const q7_t *p_wt = ker_weight;
343→        int       i;
344→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
345→
346→        vl = __riscv_vsetvl_e32m1(1);
347→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
348→
349→        for (i = 0; i < out_tensor_ch; i++)
350→        {
351→            u8_t      *p_in = (u8_t*)in_tmp_buf;
352→            uint16_t colCnt2 = colCnt;
353→
354→            //clear v0~v7
355→            vl = __riscv_vsetvl_e32m8(colCnt);
356→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
357→
358→            while (colCnt2 > 0)
359→            {
360→                vl = __riscv_vsetvl_e8m8(colCnt2);
361→                //load src1
362→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
363→                //load src2
364→                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
365→                //bump pointers and update loop counter
366→                colCnt2 -= vl;
367→                p_wt += vl;
368→                p_in += vl;
369→                //set the proper avl/SEW/LMUL values for vd4dot
370→                vl >>= 2;
371→                vl = __riscv_vsetvl_e32m8(vl);
372→                //acc += src1 * src2
373→                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
374→            }
375→
376→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
377→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
378→
379→            //2-stage shift
380→            vl = __riscv_vsetvl_e32m1(1);
381→            vSum = __riscv_vsra(vSum, pre_rshift, vl);
382→            vSum = __riscv_vmul(vSum, out_scale, vl);
383→            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
384→
385→            //scale down, clip and store the results
386→            vSum = __riscv_vmax(vSum, 0, vl);
387→            vl = __riscv_vsetvl_e16mf2(1);
388→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, post_rshift, vl);
389→            vl = __riscv_vsetvl_e8mf4(1);
390→            vuint16mf2_t vSum_u16mf2 = __riscv_vreinterpret_u16mf2(vSum_i16mf2);
391→            vuint8mf4_t vpOut = __riscv_vnclipu(vSum_u16mf2, 0, __RISCV_VXRM_RNU, vl);
392→            __riscv_vse8(pOut, vpOut, vl);
393→            pOut += vl;
394→        }
395→    }
396→#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
397→    if (pBuffer != (u8_t *)in_tmp_buf)
398→    {
399→        unsigned vl;
400→        const q7_t *p_wt = ker_weight;
401→        int       i;
402→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
403→
404→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
405→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
406→
407→        for (i = 0; i < out_tensor_ch; i++)
408→        {
409→            u8_t      *p_in = (u8_t*)in_tmp_buf;
410→            uint16_t colCnt2 = colCnt;
411→
412→            //clear v0~v7
413→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
414→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
415→
416→            while (colCnt2 > 0)
417→            {
418→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
419→                //load src1
420→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
421→                //load src2
422→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
423→                //bump pointers and update loop counter
424→                colCnt2 -= vl;
425→                p_wt += vl;
426→                p_in += vl;
427→                //set the proper avl/SEW/LMUL values for vd4dot
428→                vl >>= 2;
429→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
430→                //acc += src1 * src2
431→                NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
432→            }
433→
434→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
435→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
436→
437→            //2-stage shift
438→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
439→            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
440→            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
441→            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(post_rshift));
442→
443→            //scale down, clip and store the results
444→            NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
445→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
446→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
447→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
448→            NDS_VEC_VNCLIPU_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
449→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
450→            pOut += vl;
451→        }
452→    }
453→#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC) && (ENA_VEC_INTRINSIC)
454→    if (pBuffer != (u8_t *)in_tmp_buf)
455→    {
456→        unsigned vl;
457→        const q7_t *pA = ker_weight;
458→        int       i;
459→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
460→
461→        //set SEW for 1st time VMV_S_X
462→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
463→        vl = __riscv_vsetvl_e32m8(colCnt);
464→
465→        for (i = 0; i < out_tensor_ch; i++)
466→        {
467→            q31_t     sum = 0;
468→            u8_t      *pB = (u8_t*)in_tmp_buf;
469→            uint16_t colCnt2 = colCnt;
470→
471→            //init
472→            vint32m1_t vSum = __riscv_vmv_s_x_i32m1(sum, 1);
