 94→                                                      pre_rshift,
 95→                                                      out_scale,
 96→                                                      post_rshift,
 97→                                                      bias,
 98→                                                      pOut);
 99→                pBuffer = (u8_t *)in_tmp_buf;
100→            }
101→        }
102→    }
103→
104→    /* middle part — split x into left, mid, right */
105→    for (; i_out_y < bound_end; i_out_y++)
