681→    /*
682→     *  Here we split the entire matrix into three regions depending on the pad situation
683→     *    Top: i_out_y from 0 to pad - 1
684→     * Middle: i_out_y from pad to out_tensor_dim-pad-1
685→     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
686→     */
687→
688→    /* top part */
689→    for (i_out_y = 0; i_out_y < pad; i_out_y++)
690→    {
691→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
692→        {
693→            /* This part implements the im2col function */
694→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
695→            {
696→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
697→                {
698→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
699→                    {
700→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
701→                    }
702→                    else
703→                    {
704→                        nn_dup_u8_u16_reordered
705→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
706→                    }
707→                    pBuffer += in_tensor_ch;
708→                }
709→            }
710→
711→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
712→            {
713→                pOut =
714→                    nn_mat_mul_kernel_q7_u16_q7_reordered_2sft(ker_weight,
715→                                                               (u16_t*)in_tmp_buf,
716→                                                               out_tensor_ch,
717→                                                               in_tensor_ch * ker_dim * ker_dim,
718→                                                               pre_rshift,
719→                                                               out_scale,
720→                                                               post_rshift,
721→                                                               pOut);
722→                /* counter reset */
723→                pBuffer = (u16_t*)in_tmp_buf;
724→            }
725→        }
726→    }
727→
728→    /* middle part, here we also divide the x into left, mid and right */
729→    for (; i_out_y < out_tensor_dim - pad; i_out_y++)
730→    {
731→        /* left part */
732→        for (i_out_x = 0; i_out_x < pad; i_out_x++)
733→        {
734→            /* This part implements the im2col function */
735→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
736→            {
737→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
738→                {
739→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
740→                    {
741→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
742→                    }
743→                    else
744→                    {
745→                        nn_dup_u8_u16_reordered
746→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
747→                    }
748→                    pBuffer += in_tensor_ch;
749→                }
750→            }
751→
752→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
753→            {
754→                pOut =
755→                    nn_mat_mul_kernel_q7_u16_q7_reordered_2sft(ker_weight,
756→                                                               (u16_t*)in_tmp_buf,
757→                                                               out_tensor_ch,
758→                                                               in_tensor_ch * ker_dim * ker_dim,
759→                                                               pre_rshift,
760→                                                               out_scale,
761→                                                               post_rshift,
762→                                                               pOut);
763→                /* counter reset */
764→                pBuffer = (u16_t*)in_tmp_buf;
765→            }
766→        }
767→
768→        /* mid part */
769→        for (; i_out_x < out_tensor_dim - pad; i_out_x++)
770→        {
771→            /* This part implements the im2col function */
772→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
773→            {
774→                nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
775→                pBuffer += in_tensor_ch * ker_dim;
776→            }
777→
778→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
779→            {
780→                pOut =
781→                    nn_mat_mul_kernel_q7_u16_q7_reordered_2sft(ker_weight,
782→                                                               (u16_t*)in_tmp_buf,
783→                                                               out_tensor_ch,
784→                                                               in_tensor_ch * ker_dim * ker_dim,
785→                                                               pre_rshift,
786→                                                               out_scale,
787→                                                               post_rshift,
788→                                                               pOut);
789→                /* counter reset */
790→                pBuffer = (u16_t*)in_tmp_buf;
791→            }
792→        }
793→
794→        /* right part */
795→        for (; i_out_x < out_tensor_dim; i_out_x++)
796→        {
797→            /* This part implements the im2col function */
798→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
799→            {
800→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
801→                {
802→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
803→                    {
804→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
805→                    }
806→                    else
807→                    {
808→                        nn_dup_u8_u16_reordered
809→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
810→                    }
811→                    pBuffer += in_tensor_ch;
812→                }
813→            }
814→
815→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
816→            {
817→                pOut =
818→                    nn_mat_mul_kernel_q7_u16_q7_reordered_2sft(ker_weight,
819→                                                               (u16_t*)in_tmp_buf,
820→                                                               out_tensor_ch,
821→                                                               in_tensor_ch * ker_dim * ker_dim,
822→                                                               pre_rshift,
823→                                                               out_scale,
824→                                                               post_rshift,
825→                                                               pOut);
