 68→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim * ker_dim; //matrix_A's memory space
 69→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
