100→                }
101→            }
102→            col_counter++;
103→
104→            /* Computation is filed for [tiling_size] columns */
105→            if (col_counter == tiling_size)
106→            {
107→                pOut = nn_mat_mul_kernel_tiling_u8_s16_s8((u8_t *)in_tmp_buf,
108→                                                          src2,
109→                                                          dst_q31,
110→                                                          pOut,
111→                                                          col_counter,
112→                                                          in_tensor_ch * ker_dim * ker_dim,
113→                                                          out_tensor_ch,
114→                                                          pre_rshift,
115→                                                          out_scale,
116→                                                          post_rshift,
117→                                                          tiling_size);
118→                /* reset */
119→                col_counter = 0;
120→                pBuffer = (u8_t *)in_tmp_buf;
121→            }
122→        }
123→    }
124→
125→    /* check if there is left-over for compute */
126→    pOut = nn_mat_mul_kernel_tiling_u8_s16_s8((u8_t *)in_tmp_buf,
127→                                              src2,
128→                                              dst_q31,
129→                                              pOut,
130→                                              col_counter,
131→                                              in_tensor_ch * ker_dim * ker_dim,
132→                                              out_tensor_ch,
133→                                              pre_rshift,
134→                                              out_scale,
135→                                              post_rshift,
136→                                              tiling_size);
137→#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
138→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
139→
140→    /*
141→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
142→     *  im2col are done to output in q15_t format from q7_t input
143→     */
144→
145→    u8_t     *pBuffer = (u8_t*)in_tmp_buf;
146→    q15_t     *pOut = out_tensor;
147→    int bound_begin = (pad + stride - 1) / stride;
148→    int bound_end   = (in_tensor_dim + pad - ker_dim + stride) / stride;
149→
150→    /*
151→     *  Here we split the entire matrix into three regions depending on the pad situation
152→     *    Top: i_out_y from 0 to pad - 1
153→     * Middle: i_out_y from pad to out_tensor_dim-pad-1
154→     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
155→     */
156→
157→    /* top part */
158→    for (i_out_y = 0; i_out_y < bound_begin; i_out_y++)
159→    {
