752→                pOut =
753→                    nn_mat_mul_kernel_q7_u16_q15_reordered_2sft(ker_weight,
754→                                                                (u16_t*)in_tmp_buf,
755→                                                                out_tensor_ch,
756→                                                                in_tensor_ch * ker_dim * ker_dim,
757→                                                                pre_rshift,
758→                                                                out_scale,
759→                                                                post_rshift,
760→                                                                pOut);
761→                /* counter reset */
762→                pBuffer = (u16_t*)in_tmp_buf;
763→            }
764→        }
765→
766→        /* mid part */
767→        for (; i_out_x < out_tensor_dim - pad; i_out_x++)
768→        {
769→            /* This part implements the im2col function */
770→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
771→            {
772→                nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
773→                pBuffer += in_tensor_ch * ker_dim;
774→            }
775→
776→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
777→            {
778→                pOut =
779→                    nn_mat_mul_kernel_q7_u16_q15_reordered_2sft(ker_weight,
780→                                                                (u16_t*)in_tmp_buf,
781→                                                                out_tensor_ch,
782→                                                                in_tensor_ch * ker_dim * ker_dim,
783→                                                                pre_rshift,
784→                                                                out_scale,
785→                                                                post_rshift,
786→                                                                pOut);
