806→                        nn_dup_u8_u16_reordered
807→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
808→                    }
809→                    pBuffer += in_tensor_ch;
