872→        const q7_t *pA = ker_weight;
873→        int       i;
874→
875→        for (i = 0; i < out_tensor_ch; i++)
876→        {
877→            q31_t     sum = 0;
878→            u16_t    *pB = (u16_t*)in_tmp_buf;
879→            /* each time it process 4 entries */
880→            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
