891→                inB2 = *__SIMD32(pB)++;
892→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
893→
894→                colCnt--;
895→            }
896→            //since in_tensor_ch is multiple of 4 (input constraints), the
897→            //following codes will not be reached
898→            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
899→            // while (colCnt)
