 77→    const long col = ker_dim * ker_dim * in_tensor_ch;
 78→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
 79→
 80→    /* This part implements the im256col function */
 81→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
 82→    {
 83→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 84→        {
 85→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
 86→            {
 87→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
