171→                    else
172→                    {
173→                        nn_dup_s8
174→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
175→                    }
176→                    pBuffer += in_tensor_ch;
177→                }
178→            }
179→
180→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
181→            {
182→                pOut = nn_mat_mul_kernel_q7_q15_2sft(ker_weight,
183→                        (q7_t*)in_tmp_buf,
184→                        out_tensor_ch,
185→                        in_tensor_ch * ker_dim * ker_dim,
186→                        pre_rshift,
187→                        out_scale,
188→                        post_rshift,
189→                        pOut);
190→                /* counter reset */
191→                pBuffer = (q7_t *)in_tmp_buf;
192→            }
193→        }
194→    }
195→
196→    /* middle part, here we also divide the x into left, mid and right */
197→    for (; i_out_y < bound_end; i_out_y++)
198→    {
199→        /* left part */
200→        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
201→        {
202→            /* This part implements the im2col function */
203→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
204→            {
205→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
206→                {
207→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
208→                    {
209→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
210→                    }
211→                    else
212→                    {
213→                        nn_dup_s8
214→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
215→                    }
216→                    pBuffer += in_tensor_ch;
217→                }
218→            }
219→
220→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
221→            {
222→                pOut = nn_mat_mul_kernel_q7_q15_2sft(ker_weight,
223→                        (q7_t*)in_tmp_buf,
224→                        out_tensor_ch,
225→                        in_tensor_ch * ker_dim * ker_dim,
226→                        pre_rshift,
227→                        out_scale,
228→                        post_rshift,
229→                        pOut);
230→                /* counter reset */
231→                pBuffer = (q7_t *)in_tmp_buf;
232→            }
233→        }
234→
235→        /* mid part */
236→        for (; i_out_x < bound_end; i_out_x++)
237→        {
238→            /* This part implements the im2col function */
239→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
240→            {
241→                nn_dup_s8
242→                ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
243→                pBuffer += in_tensor_ch * ker_dim;
244→            }
245→
246→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
247→            {
248→                pOut = nn_mat_mul_kernel_q7_q15_2sft(ker_weight,
249→                        (q7_t*)in_tmp_buf,
250→                        out_tensor_ch,
251→                        in_tensor_ch * ker_dim * ker_dim,
252→                        pre_rshift,
253→                        out_scale,
254→                        post_rshift,
255→                        pOut);
256→                /* counter reset */
257→                pBuffer = (q7_t *)in_tmp_buf;
258→            }
259→        }
260→
261→        /* right part */
262→        for (; i_out_x < out_tensor_dim; i_out_x++)
263→        {
264→            /* This part implements the im2col function */
